t.script:
function downloadPdf() {
    var bar = document.querySelector('.print-bar');
    var btn = document.getElementById('rptDownloadBtn');
    if (bar) bar.style.display = 'none';
    if (btn) { btn.disabled = true; btn.textContent = 'Generating…'; }
    /* mirror @media print font reduction that html2canvas never sees */
    document.body.style.fontSize = '11px';
    var el   = document.querySelector('.report-wrapper');
    var name = (document.title || 'report').replace(/[^a-z0-9_\-]/gi, '_').toLowerCase();
    html2pdf().set({
        margin:      [12, 10, 12, 10],
        filename:    name + '.pdf',
        image:       { type: 'jpeg', quality: 0.97 },
        html2canvas: { scale: 2, useCORS: true, logging: false },
        jsPDF:       { unit: 'mm', format: 'a4', orientation: 'portrait' },
        pagebreak:   { mode: ['css', 'legacy'] }
    }).from(el).save().then(function () {
        document.body.style.fontSize = '';
        if (bar) bar.style.display = '';
        if (btn) { btn.disabled = false; btn.textContent = '⬇ Download PDF'; }
    });
}

function downloadPdf() {
    var bar = document.querySelector('.print-bar');
    var btn = document.getElementById('rptDownloadBtn');
    if (bar) bar.style.display = 'none';
    if (btn) { btn.disabled = true; btn.textContent = 'Generating…'; }
    /* mirror @media print font reduction that html2canvas never sees */
    document.body.style.fontSize = '11px';
    var el   = document.querySelector('.report-wrapper');
    var name = (document.title || 'report').replace(/[^a-z0-9_\-]/gi, '_').toLowerCase();
